図 2.1: 単振り子のアニメーション

インタラクティブ・シミュレーション
螺旋上の質点の動きをイメージするためのシミュレーションです。スライダーを動かして、パラメータ k が軌道にどう影響するか確認してください。


コード
viewof k_param = Inputs.range([-0.5, 0.5], {value: 0.15, label: "パラメータ k", step: 0.05})
viewof omega_param = Inputs.range([0.5, 5], {value: 1.5, label: "角速度 ω", step: 0.1})


















コード
import { now } from "@observablehq/stdlib"

// 状態の更新
spiral_state = {
  // アニメーションが大きくなりすぎないように時間をループさせる
  const raw_t = (now / 1000);
  const t = raw_t % 8; // 8秒でリセット

  const theta = omega_param * t;
  const a_scale = 1.0;
  const r = a_scale * Math.exp(k_param * theta);
  const x = r * Math.cos(theta);
  const y = r * Math.sin(theta);

  return {t, theta, r, x, y, a_scale};
}

// キャンバス設定
canvas_width = 400
canvas_height = 400
center_x = canvas_width / 2
center_y = canvas_height / 2
scale_factor = 20

// これまでの軌跡を描画するためのパス生成
path_points = {
  let pts = [];
  for(let th = 0; th &lt;= spiral_state.theta; th += 0.05) {
    let rad = spiral_state.a_scale * Math.exp(k_param * th);
    // Y軸は下向きが正なので反転させる
    pts.push(`${center_x + rad * Math.cos(th) * scale_factor},${center_y - rad * Math.sin(th) * scale_factor}`);
  }
  return pts.join(" ");
}

html`&lt;svg width="${canvas_width}" height="${canvas_height}" style="background-color: #f8f9fa; border: 1px solid #ddd; border-radius: 8px;"&gt;
  &lt;!-- X/Y軸 --&gt;
  &lt;line x1="0" y1="${center_y}" x2="${canvas_width}" y2="${center_y}" stroke="#ccc" stroke-dasharray="4" /&gt;
  &lt;line x1="${center_x}" y1="0" x2="${center_x}" y2="${canvas_height}" stroke="#ccc" stroke-dasharray="4" /&gt;

  &lt;!-- 軌跡 --&gt;
  &lt;polyline points="${path_points}" fill="none" stroke="#666" stroke-width="2" /&gt;

  &lt;!-- 動径ベクトル --&gt;
  &lt;line x1="${center_x}" y1="${center_y}" 
        x2="${center_x + spiral_state.x * scale_factor}" 
        y2="${center_y - spiral_state.y * scale_factor}" 
        stroke="blue" stroke-width="1.5" opacity="0.5" /&gt;

  &lt;!-- 質点 --&gt;
  &lt;circle cx="${center_x + spiral_state.x * scale_factor}" 
          cy="${center_y - spiral_state.y * scale_factor}" 
          r="6" fill="#e63946" /&gt;
&lt;/svg&gt;`
